// Central configuration helpers

// Normalize and export the external API base URL (env value includes /api/v1 already)
export const API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_API_BASE_URL || "";
  // Remove any trailing slash to avoid double slashes when concatenating paths
  return raw.replace(/\/$/, "");
})();

export const PRODUCT_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_PRODUCT_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

export const ORDER_STATUS_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_PRODUCT_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

export const ORDER_JOB_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_ORDER_JOB_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

// Workflow Engine API configuration
export const WORKFLOW_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_WORKFLOW_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

export const WORKFLOW_API_KEY = process.env.WORKFLOW_API_KEY || "";

// Helper to build full upstream URL paths safely
export function apiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  return `${API_BASE_URL}${cleaned}`;
}

export function productApiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = PRODUCT_API_BASE_URL;
  return `${base}${cleaned}`;
}

