  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = ORDER_STATUS_API_BASE_URL;
  return `${base}${cleaned}`;
}

export function orderJobApiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = ORDER_JOB_API_BASE_URL;
  return `${base}${cleaned}`;
}

export function workflowApiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = WORKFLOW_API_BASE_URL;
  return `${base}${cleaned}`;
}
